//vip.opstream12.com/share/02c67469a81aad902984219aeed24eb9","link_m3u8":"https://vip.opstream12.com/20251213/30794_02c67469/index.m3u8"}]}],"time":"45 phút/tập","description":"<p>Chàng trai trẻ Hoa Phù Sinh không màng chuyện đời, chỉ đam mê y học. Phương pháp hành nghề độc đáo khiến dân chúng trong thành vừa yêu mến vừa sợ hãi. Sau cái chết của Bách Y, Hoa Phù Sinh bị hiểu nhầm là hung thủ. Những manh mối trong bức di thư mà sư phụ để lại dường như hướng về bức \"Thiên Thư\" thần bí. Tình cờ, Văn Giác, con gái thành chủ Lương Châu, và Cố Thiên, người kế thừa tạp kỹ, cũng bị cuốn vào. Cả ba cùng nhau đến Lương Châu để điều tra. Văn Giác mượn thế lực của thành chủ giúp Phù Sinh mở một y quán ở Lương Châu, còn Cố Thiên lanh lợi hỗ trợ thu thập thông tin. Hoa Phù Sinh ở Lương Châu chữa bệnh cho dân nghèo đồng thời tìm kiếm sự thật. Tuy nhiên, những chuyện kỳ bí liên tiếp xảy ra, khiến câu đố càng trở nên phức tạp. Hoa Phù Sinh không hề hay biết rằng sự xuất hiện của mình đã âm thầm tạo ra một đợt sóng ngầm ở Lương Châu.</p>","tmdb":{"type":"tv","id":"252322","season":1,"vote_average":0,"vote_count":0},"modified":"2025-12-14T13:11:02.000Z"},{"id":"692c828bfd4c0e9b8c4598bf","_id":"692c828bfd4c0e9b8c4598bf","title":"Rock Là Thú Vui Tao Nhã Của Quý Cô","origin_name":"Rock Is a Lady's Modesty","slug":"rock-la-thu-vui-tao-nha-cua-quy-co","thumb":"/uploads/movies/rock-la-thu-vui-tao-nha-cua-quy-co-thumb.jpg","poster":"","year":2025,"type":"hoathinh","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Hoàn tất (13/13)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"Rock là thú vui tao nhã